// TAGS\n// ─────────────────────────────────────────────────\n\nmodel Tag {\n  id          String   @id @default(uuid())\n  name        String   @unique\n  slug        String   @unique\n  description String?\n  createdAt   DateTime @default(now())\n\n  articles ArticleTag[]\n\n  @@index([slug])\n}\n\nmodel ArticleTag {\n  articleId String\n  tagId     String\n  article   Article @relation(fields: [articleId], references: [id], onDelete: Cascade)\n  tag       Tag     @relation(fields: [tagId], references: [id], onDelete: Cascade)\n\n  @@id([articleId, tagId])\n}\n\n// ─────────────────────────────────────────────────\n// MEDIA (Cloudinary)\n// ─────────────────────────────────────────────────\n\nmodel Media {\n  id        String   @id @default(uuid())\n  url       String\n  publicId  String\n  altText   String?\n  width     Int?\n  height    Int?\n  createdAt DateTime @default(now())\n\n  articles ArticleMedia[]\n}\n\nmodel ArticleMedia {\n  articleId String\n  mediaId   String\n  position  Int     @default(0)\n  article   Article @relation(fields: [articleId], references: [id], onDelete: Cascade)\n  media     Media   @relation(fields: [mediaId], references: [id], onDelete: Cascade)\n\n  @@id([articleId, mediaId])\n}\n\n// ─────────────────────────────────────────────────\n// SEO METADATA (1:1 con Article)\n// ─────────────────────────────────────────────────\n\nmodel SeoMetadata {\n  id        String  @id @default(uuid())\n  articleId String  @unique\n  article   Article @relation(fields: [articleId], references: [id], onDelete: Cascade)\n\n  metaTitle       String?\n  metaDescription String?\n  ogImage         String?\n}\n\n// ─────────────────────────────────────────────────\n// ARTÍCULOS RELACIONADOS (self-referential)\n// ─────────────────────────────────────────────────\n\nmodel RelatedArticle {\n  articleId        String\n  relatedArticleId String\n  article          Article @relation(\"ArticleFrom\", fields: [articleId], references: [id], onDelete: Cascade)\n  relatedArticle   Article @relation(\"ArticleTo\", fields: [relatedArticleId], references: [id], onDelete: Cascade)\n\n  @@id([articleId, relatedArticleId])\n}\n\n// ─────────────────────────────────────────────────\n// FUENTES CIENTÍFICAS\n// ─────────────────────────────────────────────────\n\nmodel ArticleSource {\n  id        String  @id @default(uuid())\n  articleId String\n  article   Article @relation(fields: [articleId], references: [id], onDelete: Cascade)\n  title     String\n  url       String?\n  order     Int     @default(0)\n}\n\n// ─────────────────────────────────────────────────\n// EDICIONES IMPRESAS\n// ─────────────────────────────────────────────────\n\nmodel PrintEdition {\n  id            String   @id @default(uuid())\n  editionNumber Int      @unique\n  title         String\n  coverImage    String\n  issuuUrl      String\n  publishedAt   DateTime\n  isVisible     Boolean  @default(true)\n  createdAt     DateTime @default(now())\n}\n\n// ─────────────────────────────────────────────────\n// EPISODIOS DE PODCAST (YouTube)\n// ─────────────────────────────────────────────────\n\nmodel PodcastEpisode {\n  id           String   @id @default(uuid())\n  title        String\n  description  String?\n  youtubeId    String\n  thumbnailUrl String?\n  isVisible    Boolean  @default(true)\n  order        Int      @default(0)\n  publishedAt  DateTime @default(now())\n  createdAt    DateTime @default(now())\n}\n\n// ─────────────────────────────────────────────────\n// CONSEJO MÉDICO EDITORIAL\n// ─────────────────────────────────────────────────\n\nmodel CouncilMember {\n  id          String   @id @default(uuid())\n  name        String\n  role        String\n  photo       String?\n  linkedinUrl String?\n  isFeatured  Boolean  @default(false)\n  isVisible   Boolean  @default(true)\n  order       Int      @default(0)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@index([order])\n}\n",
